        // =====================================================
        // ✅ CSV → generic write (unchanged)
        // =====================================================
        private int WriteAllCsvParams(Document doc, Element e, Dictionary<string, string> row)
        {
            int count = 0;
            foreach (var kv in row)
            {
                var ps = GetAllParamsInsensitive(doc, e, kv.Key);
                if (ps == null || ps.Count == 0) continue;

                foreach (var p in ps.Where(x => x != null && !x.IsReadOnly))
                {
                    if (SetParamValue(doc, p, kv.Key, kv.Value))
                    {
                        count++;
                        break;
                    }
                }
            }
            return count;
        }

        private int WriteCsvParamsByName(Document doc, Element e, Dictionary<string, string> row, IEnumerable<string> names)
        {
            if (doc == null || e == null || row == null || names == null) return 0;

            int count = 0;
            foreach (var name in names)
            {
                if (!row.TryGetValue(name, out string raw)) continue;

                Parameter p = LookupParamInsensitive(e, name);
                if (p == null || p.IsReadOnly) continue;

                if (SetParamValue(doc, p, name, raw))
                    count++;
            }
            return count;
        }

        private Parameter LookupParamInsensitive(Element e, string name)
        {
            if (e == null || string.IsNullOrWhiteSpace(name)) return null;

            try
            {
                var p0 = e.LookupParameter(name);
                if (p0 != null) return p0;
            }
            catch { }

            try
            {
                foreach (Parameter p in e.Parameters)
                {
                    if (p?.Definition?.Name == null) continue;
                    if (string.Equals(p.Definition.Name, name, StringComparison.OrdinalIgnoreCase))
                        return p;
                }
            }
            catch { }

            return null;
        }

        private List<Parameter> GetAllParamsInsensitive(Document doc, Element e, string name)
        {
            var list = new List<Parameter>();
            if (doc == null || e == null || string.IsNullOrWhiteSpace(name)) return list;

            try
            {
                var p0 = e.LookupParameter(name);
                if (p0 != null) list.Add(p0);
            }
            catch { }

            try
            {
                foreach (Parameter p in e.Parameters)
                {
                    if (p?.Definition?.Name == null) continue;
                    if (string.Equals(p.Definition.Name, name, StringComparison.OrdinalIgnoreCase))
                        list.Add(p);
                }
            }
            catch { }

            try
            {
                ElementId tid = e.GetTypeId();
                if (tid != ElementId.InvalidElementId)
                {
                    var t = doc.GetElement(tid) as ElementType;
                    if (t != null)
                    {
                        var tp0 = t.LookupParameter(name);
                        if (tp0 != null) list.Add(tp0);

                        foreach (Parameter p in t.Parameters)
                        {
                            if (p?.Definition?.Name == null) continue;
                            if (string.Equals(p.Definition.Name, name, StringComparison.OrdinalIgnoreCase))
                                list.Add(p);
                        }
                    }
                }
            }
            catch { }

            return list.Distinct().ToList();
        }

        private bool SetParamValue(Document doc, Parameter p, string paramName, string raw)
        {
            if (p == null) return false;
            if (string.IsNullOrWhiteSpace(raw)) return false;

            raw = raw.Trim();

            try
            {
                switch (p.StorageType)
                {
                    case StorageType.Double:
                        {
                            try
                            {
                                if (p.SetValueString(raw))
                                    return true;
                            }
                            catch { }

                            double v = ParseDouble(raw);
                            double internalV = ConvertToInternalIfNeeded(paramName, v);
                            p.Set(internalV);
                            return true;
                        }

                    case StorageType.Integer:
                        {
                            if (bool.TryParse(raw, out bool bb))
                            {
                                p.Set(bb ? 1 : 0);
                                return true;
                            }

                            p.Set((int)Math.Round(ParseDouble(raw)));
                            return true;
                        }

                    case StorageType.String:
                        {
                            p.Set(raw);
                            return true;
                        }
                }
            }
            catch { }

            return false;
        }

        private int Set(Document doc, Element e, string name, object val)
        {
            if (e == null || string.IsNullOrWhiteSpace(name) || val == null) return 0;

            Parameter p = LookupParamInsensitive(e, name);
            if (p == null || p.IsReadOnly) return 0;

            try
            {
                if (p.StorageType == StorageType.Integer)
                {
                    if (val is bool b)
                    {
                        p.Set(b ? 1 : 0);
                        return 1;
                    }
                    if (val is string sBool && bool.TryParse(sBool.Trim(), out bool bb))
                    {
                        p.Set(bb ? 1 : 0);
                        return 1;
                    }
                    p.Set(Convert.ToInt32(val));
                    return 1;
                }

                if (p.StorageType == StorageType.String)
                {
                    p.Set(val.ToString());
                    return 1;
                }

                if (p.StorageType == StorageType.Double)
                {
                    double v;
                    if (val is string sd) v = ParseDouble(sd);
                    else v = Convert.ToDouble(val);

                    double internalV = ConvertToInternalIfNeeded(name, v);
                    p.Set(internalV);
                    return 1;
                }

                try
                {
                    if (p.SetValueString(val.ToString()))
                        return 1;
                }
                catch { }

                return 0;
            }
            catch { return 0; }
        }

        private double ConvertToInternalIfNeeded(string paramName, double metricValue)
        {
            if (string.IsNullOrWhiteSpace(paramName)) return metricValue;

            string n = paramName.Trim().ToLowerInvariant();

            if (n.EndsWith("_m2"))
                return UnitUtils.ConvertToInternalUnits(metricValue, UnitTypeId.SquareMeters);

            if (n.EndsWith("_m3"))
                return UnitUtils.ConvertToInternalUnits(metricValue, UnitTypeId.CubicMeters);

            if (n.EndsWith("_mm"))
                return UnitUtils.ConvertToInternalUnits(metricValue / 1000.0, UnitTypeId.Meters);

            if (n.EndsWith("_m"))
                return UnitUtils.ConvertToInternalUnits(metricValue, UnitTypeId.Meters);

            // ✅ NEW: degrees -> internal radians (Angle)
            if (n.EndsWith("_deg"))
                return UnitUtils.ConvertToInternalUnits(metricValue, UnitTypeId.Degrees);

            return metricValue;
        }

        private void WriteReportToProjectInformation(Document doc, string paramName, string reportText)
        {
            if (doc == null || string.IsNullOrWhiteSpace(paramName)) return;

            Element projInfo = doc.ProjectInformation;
            if (projInfo == null) return;

            Parameter p = LookupParamInsensitive(projInfo, paramName);
            if (p == null || p.IsReadOnly) return;

            try
            {
                if (p.StorageType == StorageType.String)
                    p.Set(reportText ?? "");
            }
            catch { }
        }

        // =====================================================
        // ✅ DeepSeek LEED plan (UPDATED schema for lt_vlt & lt_glare_risk_class)
        // =====================================================
        private LeedPlan CallDeepSeekLeedPlan(Dictionary<string, string> metrics, out string raw)
        {
            string key = GetApiKey();

            string systemPrompt =
@"You are a LEED building retrofit consultant.
Use the given building metrics to propose retrofit strategies and parameter values.
Return ONLY valid JSON with this structure (no markdown, no extra text):

{
  ""ea"": {
    ""targets"": {
      ""pv_panel_count"": int,
      ""pv_added_area_m2"": number,
      ""pv_layout_status"": string,
      ""shading_depth_m"": number,
      ""shading_count"": int,
      ""shading_status"": string
    },
    ""strategy"": {
      ""ea_roof_pv_strategy"": ""none|limited|full"",
      ""ea_roof_pv_system_type"": ""attached|mounted|bipv"",
      ""ea_roof_structural_capacity_flag"": true|false,
      ""ea_window_shading_strategy"": ""none|fixed|adjustable"",
      ""ea_window_upgrade_strategy"": ""baseline|low_e_double|triple|frame_upgrade"",
      ""ea_wall_envelope_strategy"": ""baseline|insulated_upgrade|high_performance"",
      ""ea_floor_thermal_strategy"": ""baseline|insulated""
    }
  },
  ""ss"": {
    ""strategies"": {
      ""ss_roof_heat_strategy"": ""none|green_roof|cool_roof""
    },
    ""summary"": ""..."",
    ""recommendations"": [""...""]
  },
  ""we"": {
    ""targets"": {
      ""we_rainwater_storage_capacity_m3"": number,
      ""we_water_efficiency_level"": ""low|medium|high""
    },
    ""strategies"": {
      ""we_roof_rainwater_strategy"": ""none|basic|enhanced"",
      ""we_floor_permeability_strategy"": ""impervious|semi_permeable|permeable""
    },
    ""summary"": ""..."",
    ""recommendations"": [""...""]
  },
  ""lt"": {
    ""targets"": {
      ""lt_constraint_flag"": true|false,
      ""lt_retrofit_intensity_factor"": number,
      ""lt_vlt"": number,
      ""lt_glare_risk_class"": ""low|medium|high""
    },
    ""summary"": ""..."",
    ""recommendations"": [""...""]
  },
  ""assumptions"": [""...""]
}

Rules:
- Fill ALL strategy fields with one of the allowed enum values.
- lt_vlt should be between 0 and 1.
- lt_glare_risk_class must be one of: low, medium, high.
- Keep summaries short; recommendations as an engineering checklist.
- If data is missing, put it in assumptions and keep strategy conservative.
- Do NOT include any fields outside this JSON.";

            var sb = new StringBuilder("Building metrics (from CSV selected row):\n");
            foreach (var kv in metrics)
                sb.AppendLine($"- {kv.Key}: {kv.Value}");

            using (var http = new HttpClient())
            {
                http.DefaultRequestHeaders.Authorization =
                    new AuthenticationHeaderValue("Bearer", key);

                var body = new
                {
                    model = DEEPSEEK_MODEL,
                    messages = new[]
                    {
                        new { role = "system", content = systemPrompt },
                        new { role = "user", content = sb.ToString() }
                    },
                    temperature = 0.0
                };

                string json = JsonConvert.SerializeObject(body);
                var resp = http.PostAsync(
                    "https://api.deepseek.com/chat/completions",
                    new StringContent(json, Encoding.UTF8, "application/json")
                ).GetAwaiter().GetResult();

                raw = resp.Content.ReadAsStringAsync().GetAwaiter().GetResult();

                if (!resp.IsSuccessStatusCode)
                    throw new Exception("DeepSeek API error:\n" + raw);

                dynamic root = JsonConvert.DeserializeObject<dynamic>(raw);
                string aiText = root.choices[0].message.content.ToString();

                string jsonOnly = ExtractJsonBlock(aiText);
                if (string.IsNullOrEmpty(jsonOnly))
                    throw new Exception("AI did not return valid JSON.\n\nRaw:\n" + aiText);

                return JsonConvert.DeserializeObject<LeedPlan>(jsonOnly);
            }
        }

        private string ExtractJsonBlock(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return null;

            int start = text.IndexOf('{');
            int end = text.LastIndexOf('}');

            if (start < 0 || end <= start)
                return null;

            return text.Substring(start, end - start + 1);
        }

        private string GetApiKey()
        {
            var key = Environment.GetEnvironmentVariable("DEEPSEEK_API_KEY");
            if (string.IsNullOrWhiteSpace(key))
                throw new Exception("Missing environment variable: DEEPSEEK_API_KEY");
            return key.Trim().Replace("\r", "").Replace("\n", "");
        }

        // =====================================================
        // ✅ Build report text
        // =====================================================
        private string BuildHumanReportText(LeedPlan plan, Dictionary<string, string> metrics)
        {
            var sb = new StringBuilder();
            sb.AppendLine("LEED Retrofit Guidance Report");
