            sb.AppendLine();

            // ================= WE =================
            sb.AppendLine("WE (Water Efficiency)");
            sb.AppendLine("----------------------------------------");
            if (plan.we?.targets != null)
            {
                sb.AppendLine($"we_rainwater_storage_capacity_m3: {plan.we.targets.we_rainwater_storage_capacity_m3}");
                sb.AppendLine($"we_water_efficiency_level: {plan.we.targets.we_water_efficiency_level}");
