            if (plan.lt?.targets != null)
            {
                sb.AppendLine($"lt_constraint_flag: {plan.lt.targets.lt_constraint_flag}");
                sb.AppendLine($"lt_retrofit_intensity_factor: {plan.lt.targets.lt_retrofit_intensity_factor}");
                sb.AppendLine($"lt_vlt: {plan.lt.targets.lt_vlt}");
                sb.AppendLine($"lt_glare_risk_class: {plan.lt.targets.lt_glare_risk_class}");
            }
            else sb.AppendLine("lt.targets: (null)");

            if (!string.IsNullOrWhiteSpace(plan.lt?.summary))
                sb.AppendLine($"summary: {plan.lt.summary}");

            if (plan.lt?.recommendations != null && plan.lt.recommendations.Count > 0)
            {
                sb.AppendLine("recommendations:");
                foreach (var r in plan.lt.recommendations)
                    sb.AppendLine($"- {r}");
            }
            sb.AppendLine();

            // ================= assumptions =================
            if (plan.assumptions != null && plan.assumptions.Count > 0)
            {
                sb.AppendLine("Assumptions");
                sb.AppendLine("----------------------------------------");
                foreach (var a in plan.assumptions)
                    sb.AppendLine($"- {a}");
                sb.AppendLine();
            }

            return sb.ToString();
        }


        // =====================================================
        // CSV helpers
        // =====================================================
        private double ParseDouble(string s)
        {
            s = (s ?? "").Trim().Replace(",", ".");
            double.TryParse(
                s,
                System.Globalization.NumberStyles.Any,
                System.Globalization.CultureInfo.InvariantCulture,
                out double v
            );
            return v;
        }

        private string SelectCSVFile()
        {
            var dlg = new Microsoft.Win32.OpenFileDialog
            {
                Filter = "CSV Files (*.csv)|*.csv",
                Title = "Select QGIS CSV Export"
            };
            return dlg.ShowDialog() == true ? dlg.FileName : null;
        }

        private string SelectReportOutputFolder()
        {
            try
            {
                using (var dlg = new System.Windows.Forms.FolderBrowserDialog())
                {
                    dlg.Description = "Select folder to export LEED report TXT";
                    dlg.ShowNewFolderButton = true;
                    var result = dlg.ShowDialog();
                    return result == System.Windows.Forms.DialogResult.OK ? dlg.SelectedPath : null;
                }
            }
            catch { return null; }
        }

        private void ShowTimedPopup(string title, string text, int seconds)
        {
            try
            {
                using (var f = new System.Windows.Forms.Form())
                {
                    f.Text = title;
                    f.FormBorderStyle = System.Windows.Forms.FormBorderStyle.FixedDialog;
                    f.StartPosition = System.Windows.Forms.FormStartPosition.CenterScreen;
                    f.MaximizeBox = false;
                    f.MinimizeBox = false;
                    f.TopMost = true;
                    f.ShowInTaskbar = false;
                    f.Width = 520;
                    f.Height = 160;

                    var lbl = new System.Windows.Forms.Label();
                    lbl.Text = text;
                    lbl.AutoSize = false;
                    lbl.Dock = System.Windows.Forms.DockStyle.Fill;
                    lbl.TextAlign = System.Drawing.ContentAlignment.MiddleCenter;
                    lbl.Font = new System.Drawing.Font("Segoe UI", 10f, System.Drawing.FontStyle.Regular);
                    f.Controls.Add(lbl);

                    var timer = new System.Windows.Forms.Timer();
                    timer.Interval = Math.Max(1, seconds) * 1000;
                    timer.Tick += (s, e) =>
                    {
                        timer.Stop();
                        try { f.Close(); } catch { }
                    };
                    timer.Start();

                    f.ShowDialog();
                }
            }
            catch { }
        }
    }

